+/// Wraps a SQL string literal with single quotes and escapes embedded quotes.
+auto quote_string_literal(std::string_view value) -> std::string {
+  auto result = std::string{"'"};
+  for (auto c : value) {
+    if (c == '\'') {
+      result += "''";
+    } else {
+      result += c;
+    }
+  }
+  result += '\'';
+  return result;
+}
